B.Ls=new A.aN(B.c_,"Emergency language must be precise","Emergency communications follow strict ICAO phraseology. In sentence completion questions, you must choose the word or phrase that **precisely and completely** fills the meaning of the sentence.\n\nThe distractor options often look plausible \u2014 the key is selecting the **most accurate** aviation term.",null,null,null)
B.LS=new A.aN(B.aL,"\ud83d\udea8 Emergency Levels",'**MAYDAY** (\xd73) \u2014 Distress: immediate danger to life\n"MAYDAY MAYDAY MAYDAY \u2014 THY123 \u2014 engine fire \u2014 declaring emergency"\n\n**PAN-PAN** (\xd73) \u2014 Urgency: serious situation, not immediate danger\n"PAN-PAN PAN-PAN PAN-PAN \u2014 THY123 \u2014 medical emergency on board"\n\n**SQUAWK 7700** \u2014 General emergency\n**SQUAWK 7600** \u2014 Radio failure\n**SQUAWK 7500** \u2014 Unlawful interference (hijack)',null,null,null)
B.M7=new A.aN(B.aL,"\ud83d\udce1 Emergency Checklist Language",'Emergency checklists use specific sentence patterns:\n\u2022 "In the event of \u2026\u2026\u2026, the crew should\u2026"\n\u2022 "If \u2026\u2026\u2026 is observed, immediately\u2026"\n\u2022 "\u2026\u2026\u2026\u2026 and report to ATC"\n\u2022 "Declare \u2026\u2026\u2026\u2026 and request priority landing"\n\nCommon verbs: **declare, squawk, divert, dump, depressurize, evacuate, report**',null,null,null)
B.Ix=new A.cc("In the event of an engine fire, the crew must __________ the affected engine.","Motor yang\u0131n\u0131 durumunda, ekip etkilenen motoru kapatmal\u0131d\u0131r.","shut down")
